import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    final rp = ReceivePort();
    _sendPort.send((req, rp.sendPort));
    try {
      final msg = await rp.first;
      if (msg is CpuTileRenderResponse) return msg;
      if (msg is _CpuTileRenderFailure) throw msg.toException();
      throw StateError('Unexpected CPU tile worker reply: ${msg.runtimeType}');
    } finally {
      rp.close();
    }
  }

  void dispose() {
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }
}

/// Exception surfaced when the worker isolate could not render a requested tile.
class CpuTileWorkerException implements Exception {
  const CpuTileWorkerException({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  @override
  String toString() => 'CpuTileWorkerException($errorType): $message';
}

final class _CpuTileRenderFailure {
  const _CpuTileRenderFailure({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  factory _CpuTileRenderFailure.from(Object error, StackTrace stackTrace) {
    return _CpuTileRenderFailure(
      errorType: error.runtimeType.toString(),
      message: error.toString(),
      stackTraceText: stackTrace.toString(),
    );
  }

  CpuTileWorkerException toException() {
    return CpuTileWorkerException(
      errorType: errorType,
      message: message,
      stackTraceText: stackTraceText,
    );
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    SendPort? replyTo;
    try {
      final (CpuTileRenderRequest req, SendPort port) =
          msg as (CpuTileRenderRequest, SendPort);
      replyTo = port;
      final resp = renderCpuTileInIsolate(req);
      replyTo.send(resp);
    } catch (error, stackTrace) {
      replyTo?.send(_CpuTileRenderFailure.from(error, stackTrace));
    }
  });
}

import 'dart:typed_data';

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';
import 'cpu_viewport_mapping.dart';

/// Message used to request a CPU frame render from an isolate.
final class CpuRenderRequest {
  const CpuRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.width,
    required this.height,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;
  final int width;
  final int height;
  final int sampleCount;
}

final class CpuRenderResponse {
  const CpuRenderResponse({
    required this.rgba,
    required this.width,
    required this.height,
  });

  /// RGBA8888 bytes.
  final Uint8List rgba;
  final int width;
  final int height;
}

/// Top-level entrypoint suitable for [Isolate.run].
CpuRenderResponse renderCpuFrameInIsolate(CpuRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    // Full viewport
    fullWidth: req.width,
    fullHeight: req.height,
    // Tile == full
    x0: 0,
    y0: 0,
    w: req.width,
    h: req.height,
    sampleCount: req.sampleCount,
  );
  return CpuRenderResponse(rgba: bytes, width: req.width, height: req.height);
}

final class CpuTileRenderRequest {
  const CpuTileRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;
  final int sampleCount;
}

final class CpuTileRenderResponse {
  const CpuTileRenderResponse({
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.rgba,
  });

  final int x0;
  final int y0;
  final int w;
  final int h;
  final Uint8List rgba;
}

final class CpuViewportCoordinate {
  const CpuViewportCoordinate(this.x, this.y);

  final double x;
  final double y;
}

/// Explicit dimensions contract for CPU render work.
final class CpuRenderDimensions {
  const CpuRenderDimensions({required this.width, required this.height});

  final int width;
  final int height;

  void validate() {
    if (width <= 0 || height <= 0) {
      throw ArgumentError.value(
        (width, height),
        'full viewport',
        'must be positive',
      );
    }
  }
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Explicit point contract for a CPU pixel sample inside a full viewport.
final class CpuRenderSamplePoint {
  const CpuRenderSamplePoint({
    required this.fullWidth,
    required this.fullHeight,
    required this.x,
    required this.y,
  });

  final int fullWidth;
  final int fullHeight;
  final int x;
  final int y;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (x < 0 || y < 0 || x >= fullWidth || y >= fullHeight) {
      throw ArgumentError.value(
        (x, y),
        'sample coordinate',
        'must be inside the full viewport',
      );
    }
  }
}

/// Maps a pixel sample to the CPU fractal plane.
///
/// [sampleOffsetX] and [sampleOffsetY] are normalized offsets within the pixel
/// (0.5 means pixel center). Dividing by the full dimensions keeps one-pixel
/// renders centered on pan and keeps opposite edge pixel centers symmetric.
CpuViewportCoordinate cpuViewportCoordinateForSample({
  required double panX,
  required double panY,
  required double zoom,
  required int fullWidth,
  required int fullHeight,
  required int x,
  required int y,
  required double sampleOffsetX,
  required double sampleOffsetY,
}) {
  CpuRenderSamplePoint(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x: x,
    y: y,
  ).validate();

  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );
  final nx = viewport.normalizedSampleOffset(
    pixel: x,
    extent: fullWidth,
    sampleOffset: sampleOffsetX,
  );
  final ny = viewport.normalizedSampleOffset(
    pixel: y,
    extent: fullHeight,
    sampleOffset: sampleOffsetY,
  );
  final coordinate = viewport.coordinate(nx: nx, ny: ny);

  return CpuViewportCoordinate(coordinate.$1, coordinate.$2);
}

CpuTileRenderResponse renderCpuTileInIsolate(CpuTileRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    fullWidth: req.fullWidth,
    fullHeight: req.fullHeight,
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    sampleCount: req.sampleCount,
  );

  return CpuTileRenderResponse(
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    rgba: bytes,
  );
}

Uint8List _renderRect({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  CpuRenderRect(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
  ).validate();

  final bytes = Uint8List(w * h * 4);
  final sampleGrid = CpuSampleGrid.fromRequestedCount(sampleCount);

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);
  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < sampleGrid.samplesPerAxis; sy++) {
        for (int sx = 0; sx < sampleGrid.samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: fullWidth,
            sample: sx,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: fullHeight,
            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

import 'dart:async';
import 'dart:typed_data';
import 'dart:ui' as ui;

import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import '../validation/render_validation.dart';
import '../validation/convergence_detector.dart';
import 'cpu_formulas.dart';
import 'cpu_render_isolate.dart';
import 'cpu_tile_worker.dart';
import 'cpu_iteration_budget.dart';
import 'cpu_iterators.dart';
import 'cpu_viewport_mapping.dart';

/// Very small CPU fallback renderer for 2D fractals.
///
/// Deep-zoom quality path:
/// - Uses double-precision math on CPU for stable deep zoom coordinates.
/// - Uses multi-sample anti-aliasing (2x2) to reduce grain/noise.
/// - Uses smooth/continuous escape-time coloring.
class CpuFractalRenderer extends StatefulWidget {
  final FractalModule module;
  final FractalRenderState state;

  /// Target render resolution (will be scaled to fit).
  final int width;
  final int height;

  /// Called when a partial CPU frame is available.
  final VoidCallback? onPartial;

  /// Called when slow mode active state changes.
  final ValueChanged<bool>? onSlowModeActiveChanged;

  const CpuFractalRenderer({
    super.key,
    required this.module,
    required this.state,
    this.width = 360,
    this.height = 360,
    this.onPartial,
    this.onSlowModeActiveChanged,
  });

  @override
  State<CpuFractalRenderer> createState() => _CpuFractalRendererState();
}

class _CpuFractalRendererState extends State<CpuFractalRenderer> {
  ui.Image? _image;
  Object? _error;
  int _job = 0;
  Timer? _debounce;
  Timer? _refineTimer;
  RenderCheckResult? _lastValidation;

  // Convergence detection for adaptive iteration adjustment.
  final ConvergenceDetector _convergenceDetector = const ConvergenceDetector();
  Uint8List? _previousFrameBuffer;
  bool _isConverged = false;

  CpuTileWorker? _worker;

  int? _slowModeRow;
  int? _slowModeTotal;
  bool _slowModeActive = false;

  // Preview vs refine rendering.
  DateTime? _lastInteractionAt;

  @override
  void initState() {
    super.initState();
    _spawnWorker();
  }

  Future<void> _spawnWorker() async {
    try {
      _worker = await CpuTileWorker.spawn();
      if (!mounted) {
        _worker?.dispose();
        return;
      }
      _scheduleRender();
    } catch (e) {
      if (mounted) setState(() => _error = e);
    }
  }

  @override
  void didUpdateWidget(covariant CpuFractalRenderer oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.module.id != widget.module.id ||
        oldWidget.state.view.zoom != widget.state.view.zoom ||
        oldWidget.state.view.pan != widget.state.view.pan ||
        oldWidget.state.params != widget.state.params) {
      _markInteraction();
      _scheduleRender();
    }
  }

  @override
  void dispose() {
    _debounce?.cancel();
    _refineTimer?.cancel();
    _setSlowModeActive(false);
    _worker?.dispose();
    _image?.dispose();
    super.dispose();
  }

  void _markInteraction() {
    _lastInteractionAt = DateTime.now();
    // Reset convergence state on new interaction.
    _isConverged = false;
  }

  /// Checks frame-to-frame convergence and updates iteration budget.
  /// Returns adjusted iteration count based on convergence result.
  int _checkConvergence(
      Uint8List currentBuffer, int width, int height, int currentIterations) {
    final prev = _previousFrameBuffer;

    if (prev == null || prev.length != currentBuffer.length) {
      // First frame - store and return current iterations.
      _previousFrameBuffer = Uint8List.fromList(currentBuffer);
      _isConverged = false;
      return currentIterations;
    }

    // Compare with previous frame.
    final result = _convergenceDetector.detect(
      previous: prev,
      current: currentBuffer,
      width: width,
      height: height,
      currentIterations: currentIterations,
    );

    // Store current buffer for next comparison.
    _previousFrameBuffer = Uint8List.fromList(currentBuffer);
    _isConverged = result.converged;

    // Log convergence state in debug mode.
    if (kDebugMode && result.changeRatio > 0.01) {
      debugPrint('[cpu] convergence: converged=${result.converged} '
          'change=${(result.changeRatio * 100).toStringAsFixed(1)}% '
          'iter=$currentIterations->${result.suggestedIterations}');
    }

    // Use suggested iterations for next render if not converged.
    return result.suggestedIterations.clamp(50, _iterationMaxForModule());
  }

  bool _shouldStillBeInteracting() {
    final t = _lastInteractionAt;
    if (t == null) return false;
    return DateTime.now().difference(t) < const Duration(milliseconds: 220);
  }

  void _scheduleRender() {
    _debounce?.cancel();
    _debounce = Timer(const Duration(milliseconds: 60), _renderPreview);

    // Schedule a refine pass after user stops touching.
    _refineTimer?.cancel();
    _refineTimer = Timer(const Duration(milliseconds: 260), () {
      if (!mounted) return;
      if (_shouldStillBeInteracting()) {
        // Still moving; we'll get rescheduled by later updates.
        return;
      }
      // Skip refine pass if the preview frame already converged — no
      // visible change would result from the extra CPU work.
      if (_isConverged) return;
      _renderRefine();
    });
  }

  void _setSlowModeActive(bool active) {
    if (_slowModeActive == active) return;
    if (mounted) {
      setState(() {
        _slowModeActive = active;
      });
    } else {
      _slowModeActive = active;
    }
    widget.onSlowModeActiveChanged?.call(active);
  }

  static const int _tileSize = 96;

  List<(int x0, int y0, int w, int h)> _tileOrder({
    required int width,
    required int height,
  }) {
    final cols = (width / _tileSize).ceil();
    final rows = (height / _tileSize).ceil();

    final startX = (cols - 1) ~/ 2;
    final startY = (rows - 1) ~/ 2;

    final out = <(int, int, int, int)>[];
    final seen = List.generate(rows, (_) => List<bool>.filled(cols, false));

    void addTile(int tx, int ty) {
      if (tx < 0 || ty < 0 || tx >= cols || ty >= rows) return;
      if (seen[ty][tx]) return;
      seen[ty][tx] = true;

      final x0 = tx * _tileSize;
      final y0 = ty * _tileSize;
      final w = (x0 + _tileSize <= width) ? _tileSize : (width - x0);
      final h = (y0 + _tileSize <= height) ? _tileSize : (height - y0);
      if (w <= 0 || h <= 0) return;
      out.add((x0, y0, w, h));
    }

    // Classic spiral walk over the tile grid.
    int x = startX;
    int y = startY;
    int dx = 1;
    int dy = 0;
    int segmentLen = 1;
    int segmentPassed = 0;
    int segments = 0;

    while (out.length < cols * rows) {
      addTile(x, y);
      x += dx;
      y += dy;
      segmentPassed++;

      if (segmentPassed == segmentLen) {
        segmentPassed = 0;
        // rotate right
        final ndx = -dy;
        final ndy = dx;
        dx = ndx;
        dy = ndy;
        segments++;
        if (segments % 2 == 0) segmentLen++;
      }

      // Safety: break if we somehow loop forever.
      if (segmentLen > cols + rows + 4) break;
    }

    return out;
  }

  Future<CpuRenderFrame> _renderFrameTiled({
    required int width,
    required int height,
    required int iterations,
    required double bailout,
    required Vector2 juliaC,
    required int sampleCount,
    required int job,
    required Duration? maxTime,
    required ValueChanged<ui.Image> onPartial,
  }) async {
    final full = Uint8List(width * height * 4);
    // Start with an opaque background so partial-tile progressive updates don't
    // look like "missing" regions (transparent pixels showing the UI behind).
    for (int i = 3; i < full.length; i += 4) {
      full[i] = 255;
    }
    final started = DateTime.now();

    int tilesDone = 0;
    DateTime lastUpdate = DateTime.fromMillisecondsSinceEpoch(0);

    for (final tile in _tileOrder(width: width, height: height)) {
      if (!mounted || job != _job) break;

      if (maxTime != null && DateTime.now().difference(started) > maxTime) {
        break;
      }

      final req = CpuTileRenderRequest(
        moduleId: widget.module.id,
        panX: widget.state.view.pan.x,
        panY: widget.state.view.pan.y,
        zoom: widget.state.view.zoom,
        iterations: iterations,
        bailout: bailout,
        juliaCX: juliaC.x,
        juliaCY: juliaC.y,
        fullWidth: width,
        fullHeight: height,
        x0: tile.$1,
        y0: tile.$2,
        w: tile.$3,
        h: tile.$4,
        sampleCount: sampleCount,
      );

      final worker = _worker;
      if (worker == null)
        return CpuRenderFrame(rgba: full, width: width, height: height);
      final resp = await worker.renderTile(req);

      // Blit tile into full buffer.
      for (int ty = 0; ty < resp.h; ty++) {
        final dstRow = ((resp.y0 + ty) * width + resp.x0) * 4;
        final srcRow = (ty * resp.w) * 4;
        full.setRange(
          dstRow,
          dstRow + resp.w * 4,
          resp.rgba,
          srcRow,
        );
      }

      tilesDone++;

      // Progressive UI update (throttled).
      final now = DateTime.now();
      final shouldUpdate = tilesDone == 1 ||
          tilesDone % 6 == 0 ||
          now.difference(lastUpdate) > const Duration(milliseconds: 80);
      if (shouldUpdate) {
        lastUpdate = now;
        final img =
            await CpuRenderFrame(rgba: full, width: width, height: height)
                .toImage();
        if (!mounted || job != _job) break;
        onPartial(img);
      }
    }

    return CpuRenderFrame(rgba: full, width: width, height: height);
  }

  Future<void> _renderPass({
    required double resolutionScale,
    required int sampleCount,
    Duration? maxTime,
    bool isPreview = false,
  }) async {
    final int job = ++_job;
    try {
      final baseIterations = readInt(widget.state.params, 'iterations', 220);
      final maxIterations = _iterationMaxForModule();
      final control = cpuControlScalarForModule(
        widget.module.id,
        widget.state.params,
      );
      final juliaC = cpuJuliaCForModule(widget.module.id, widget.state.params);

      // Increase iteration budget as zoom increases to avoid blotchy boundaries.
      final iterations = CpuIterationBudget.forZoom(
        baseIterations: baseIterations,
        maxIterations: maxIterations,
        zoom: widget.state.view.zoom,
      );

      final w = resolutionScale < 1.0
          ? (widget.width * resolutionScale).round().clamp(200, widget.width)
          : widget.width;
      final h = resolutionScale < 1.0
          ? (widget.height * resolutionScale).round().clamp(200, widget.height)
          : widget.height;

      var frame = await _renderFrameTiled(
        width: w,
        height: h,
        iterations: iterations,
        bailout: control,
        juliaC: juliaC,
        sampleCount: sampleCount,
        job: job,
        maxTime: maxTime,
        onPartial: (img) {
          if (!mounted || job != _job) return;
          final oldImage = _image;
          setState(() {
            _image = img;
            _error = null;
          });
          oldImage?.dispose();
          widget.onPartial?.call();
        },
      );

      // Ensure user always sees something.
      if (_isNearlyBlack(frame.rgba)) {
        final fallback = _fallbackView(widget.module);
        final req = CpuTileRenderRequest(
          moduleId: widget.module.id,
          panX: fallback.$1.x,
          panY: fallback.$1.y,
